import{_ as e,o,c as a,U as t}from"./chunks/framework.0a7cadb5.js";const s="/oort/assets/oort-screenshot-uploading.4ee421d5.png",g=JSON.parse('{"title":"Arcsecond Oort Uploader","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"},l=t(`<p><img src="https://statics.arcsecond.io/img/logo-circle-sm.png" alt="img"></p><h1 id="arcsecond-oort-uploader" tabindex="-1">Arcsecond Oort Uploader <a class="header-anchor" href="#arcsecond-oort-uploader" aria-label="Permalink to &quot;Arcsecond Oort Uploader&quot;">​</a></h1><p>The open-source easy-to-use tool for uploading data to Arcsecond.io.</p><h2 id="quick-start-for-observatory-portals" tabindex="-1">Quick start for Observatory Portals <a class="header-anchor" href="#quick-start-for-observatory-portals" aria-label="Permalink to &quot;Quick start for Observatory Portals&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pip</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort-cloud</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">login</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">watch</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#C3E88D;">folde</span><span style="color:#A6ACCD;">r</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">start</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">uploader</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&gt;&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">stdout_and_stderr.log</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">2&gt;&amp;1</span></span></code></pre></div><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Oort is Arcsecond&#39;s uploader tool. <a href="https://www.arcsecond.io" target="_blank" rel="noreferrer">Arcsecond.io</a> is a comprehensive cloud platform for astronomical observations, for individual astronomers and observatories. Hence, Oort can be used by individuals to upload their data to their Arcsecond account, or observatories to their portal.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To open an Observatory Portal, simply visit your Arcsecond settings <a href="https://www.arcsecond.io/profile#memberships" target="_blank" rel="noreferrer">here</a> and click &quot;Create Portal&quot;.</p></div><p><strong>Oort is a pure uploading tool, not a two-ways syncing tool.</strong> A file that is deleted locally will remain in the cloud if already uploaded. Change of files in the cloud have no effect locally either.</p><p>Oort has been thoroughly tested on recent Linux and macOS operating systems (it may need some tweaks on Windows).</p><h2 id="installation-update" tabindex="-1">Installation &amp; Update <a class="header-anchor" href="#installation-update" aria-label="Permalink to &quot;Installation &amp; Update&quot;">​</a></h2><p>Use pip (see <a href="https://pip.pypa.io/en/stable/installing/" target="_blank" rel="noreferrer">this page</a> on how to install pip, if you haven&#39;t done so):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pip</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort-cloud</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The Pypi database already contains an <code>oort</code> package (without the <code>-cloud</code> suffix) and it has nothing to do with ours.</p></div><p>Install for the user only (non-root):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pip</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort-cloud</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--user</span></span></code></pre></div><p>Upgrade oort-cloud:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pip</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort-cloud</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--upgrade</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Even if our package is named <code>oort-cloud</code>, all commands start with the simple <code>oort</code> string.</p></div><p>Then, make sure to login first with oort before uploading:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">login</span></span></code></pre></div><p>Logging in through oort will retrieve your personal Upload Key that will be placed inside <code>~/.oort/config.ini</code>. <strong>Do not share this key.</strong></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>This key is not your personal API Key. The Upload Key has just enough permission to upload data on your behalf, and it cannot give access to your account. It can also be reset from your Arcsecond <a href="https://www.arcsecond.io/profile#keys" target="_blank" rel="noreferrer">account settings</a>.</p></div><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>Oort has two modes: &quot;direct&quot; and &quot;batch&quot;.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>As of now, the two modes are mutually exclusive (because of the access to the small local SQLite database). You must <strong>not</strong> have oort batch mode running if you want to use the direct mode. If you need to use the direct mode, stop the batch mode first.</p></div><h3 id="direct-mode" tabindex="-1">Direct mode <a class="header-anchor" href="#direct-mode" aria-label="Permalink to &quot;Direct mode&quot;">​</a></h3><p>Oort can be used in a pure &quot;upload this folder right now, please&quot; manner, also called the &quot;direct&quot; mode. It is suited for cases where a folder contains existing files of data, and the content of the folder won&#39;t change over time. Note that if it does, the command can be safely re-run, and oort will upload new files.</p><p><strong>All non-hidden files will be uploaded.</strong> Be careful to choose folders that contain only data you want to send to the cloud. Of course, in case of a mistake, the data can later on be deleted from the various Data pages available on the web.</p><p>Here are the command for basic direct upload:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">upload</span><span style="color:#A6ACCD;"> [OPTIONS] </span><span style="color:#89DDFF;">&lt;</span><span style="color:#A6ACCD;">folder</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><p>There are five <code>OPTIONS</code>:</p><ul><li><code>-o &lt;subdomain&gt;</code> (or <code>--organisation &lt;subdomain&gt;</code>) to tell Oort to send files to an organisation account.</li><li><code>-t &lt;telescope uuid&gt;</code> (or <code>--telescope &lt;telescope uuid&gt;</code>) to specify the telescope with which that data must be associated. This option is mandatory for uploads to an organisation account, and optional for uploads to a personal account.</li><li><code>-f</code> (or <code>--force</code>) to reset the local metadata and force the re-upload of the folder&#39;s content. As always, existing files in the cloud will never be<br> modified or overwritten.</li><li><code>-z</code> (or <code>--zip</code>) to tell Oort to zip FITS and XISF files before uploading them. If they are already zipped, they won&#39;t be changed.</li><li><code>-d &lt;name or uuuid&gt;</code> (or <code>--dataset &lt;name or uuuid&gt;</code>) to tell Oort to what dataset all files of the folder (and its subfolders). must be put. The argument can either be a name or a UUID. If it is a name, Oort will try to find it. If none is found, Oort will create it. If it is a UUID, Oort will look for it. If none is found, Oort will raise an error.</li></ul><p>The <code>upload</code> command will summarise its settings and ask for confirmation before proceeding. It is a small step to ensure that no mistake have been made before starting upload.</p><h3 id="batch-background-mode" tabindex="-1">Batch / background mode <a class="header-anchor" href="#batch-background-mode" aria-label="Permalink to &quot;Batch / background mode&quot;">​</a></h3><p>In batch mode, Oort comes with a small local web server to monitor the uploader, and this is what it looks like when running: <img src="`+s+`" alt=""> (<a href="https://raw.githubusercontent.com/arcsecond-io/oort/master/docs/img/oort-screenshot-uploading.png"> enlarge</a>)</p><p>Oort batch mode works by watching for files in a folder, and automatically upload them to the cloud in the background. This mode is designed for &quot;live mode&quot; where data files are being sent to a folder, during the night. Hence the content of the folder changes over time.</p><p><strong>All non-hidden files will be uploaded.</strong> Be careful to choose folders that contain only data you want to send to the cloud. Of course, in case of a mistake, the data can later on be deleted from the various Data pages available on the web.</p><p>To start the uploader:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">start</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">uploader</span></span></code></pre></div><p>To start the monitor (optional):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">start</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">monitor</span></span></code></pre></div><p>Then, to tell Oort which folder(s) to watch for existing and future files, the command is:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">oort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">watch</span><span style="color:#A6ACCD;"> [OPTIONS] </span><span style="color:#89DDFF;">&lt;</span><span style="color:#A6ACCD;">folder</span><span style="color:#89DDFF;">1&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#A6ACCD;">folder</span><span style="color:#89DDFF;">2&gt;</span><span style="color:#A6ACCD;"> ...</span></span></code></pre></div><p>The <code>OPTIONS</code> part of <code>oort watch</code> is important. There are three options:</p><ul><li><code>-o &lt;subdomain&gt;</code> (or <code>--organisation &lt;subdomain&gt;</code>) to tell Oort to send files to an organisation account.</li><li><code>-t &lt;telescope uuid&gt;</code> (or <code>--telescope &lt;telescope uuid&gt;</code>) to specify the telescope with which that data must be associated. This option is mandatory for uploads to an organisation account, and optional for uploads to a personal account.</li><li><code>-z</code> (or <code>--zip</code>) to automatically gzip data files (FITS and XISF, other diles aren&#39;t touched) before upload. Default is False. Note that switching zip on will modify the content of the folder (replacing files with zipped ooes), hence impacting a possible backup system. Moreover, zipping will require some CPU resource. On the other hand, it will reduce the bandwidth usage and storage footprint.</li></ul><p>The <code>watch</code> command will summarise its settings and ask for confirmation before proceeding.</p><h3 id="how-does-the-batch-mode-work" tabindex="-1">How does the batch mode work? <a class="header-anchor" href="#how-does-the-batch-mode-work" aria-label="Permalink to &quot;How does the batch mode work?&quot;">​</a></h3><p>Oort provides two different processes:</p><p>• An <strong>uploader</strong>, which takes care of creating/syncing the Datasets and Datafiles objects in Arcsecond.io (either in your personal account, or your Observatory Portal). And then upload the files.</p><p>• A <strong>monitor</strong> (small local web server), which allow you to observe, control and setup what is happening in the uploader (and find what happened before too).</p><p>To avoid conflicting with a possible existing <code>supervisord</code> configuration, we chose to not manage the two processes ourselves. If you want to use the handy <a href="http://supervisord.org" target="_blank" rel="noreferrer">supervisor</a> tool to manage process, you can use the command <code>oort config</code> to get the configuration sections you should use for oort processes.</p><h3 id="why-0-0-0-0-5001" tabindex="-1">Why 0.0.0.0:5001 ? <a class="header-anchor" href="#why-0-0-0-0-5001" aria-label="Permalink to &quot;Why 0.0.0.0:5001 ?&quot;">​</a></h3><p>The little web server that Oort starts locally has the address <code><a href="http://0.0.0.0:5001" target="_blank" rel="noreferrer">http://0.0.0.0:5001</a></code>. With such IP address, the oort processes can run in the PC where data is sent to, and still being monitored from a remote PC without login.</p><p>It is particularly useful for observatories managing various PCs with different roles.</p><p>Say for instance the PC that receives all the data is PC42 and you work on PC17. Oort watch command has been issued on PC42. From PC17 you can monitor what happens on PC42 by simply visiting <code>http://&lt;ip address of pc42&gt;:5001 </code>.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>If port <code>5001</code> is already used when the monitor starts, Oort will increment it by one until it finds an available port.</p></div><h2 id="all-batch-mode-commands" tabindex="-1">All batch mode commands <a class="header-anchor" href="#all-batch-mode-commands" aria-label="Permalink to &quot;All batch mode commands&quot;">​</a></h2><p>Use:</p><ul><li><code>oort start &lt;uploader|monitor&gt;</code>, to start the uploader or the monitor.</li><li><code>oort watch &lt;folder1&gt;...</code> to start watching the content of folder(s).</li><li><code>oort folders</code> to display a list of the folders watched abd their settings.</li><li><code>oort unwatch &lt;folder_id&gt;...</code> to remove a folder from being watch. Use <code>oort folders</code> to get folder IDs.</li><li><code>oort config</code> to display the two small <code>supervisor</code> config sections you can use.</li></ul><h2 id="other-oort-commands" tabindex="-1">Other Oort commands <a class="header-anchor" href="#other-oort-commands" aria-label="Permalink to &quot;Other Oort commands&quot;">​</a></h2><p>Use:</p><ul><li><code>oort telescopes</code> to get a list of telescopes available (filtered to an organisation with the <code>-o &lt;subdomain&gt;</code> option).</li><li><code>oort login</code> to login to your personal Arcsecond.io account and fetch your personal upload key.</li><li><code>oort --version</code> to display Oort version</li><li><code>oort</code> or <code>oort --help</code> for a complete help.</li></ul><p>All commands have a dedicated help accessible with <code>oort &lt;command&gt; --help</code></p><p>There is no need of using <code>sudo</code> in any case with oort.</p><h2 id="datasets-datafiles" tabindex="-1">Datasets &amp; DataFiles <a class="header-anchor" href="#datasets-datafiles" aria-label="Permalink to &quot;Datasets &amp; DataFiles&quot;">​</a></h2><p>Oort is using the folder structure to put files inside datasets. And there is one simple rule to know:</p><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><strong>One folder (or subfolder) = One Dataset</strong>.</li><li><strong>For each (valid) folder content file, there will be one DataFile put inside the Dataset</strong></li></ul></div><p>The rule is voluntarily simple to make Oort focused and reliable. Subsequent re-organisation, renaming etc. will occur on the web.</p><p>For instance, for a folder structure on disk, where Oort has been instructed to upload the content of the folder <code>data/</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">data/</span></span>
<span class="line"><span style="color:#A6ACCD;">│   README.md</span></span>
<span class="line"><span style="color:#A6ACCD;">│   file001.txt    </span></span>
<span class="line"><span style="color:#A6ACCD;">│</span></span>
<span class="line"><span style="color:#A6ACCD;">└───folder1/</span></span>
<span class="line"><span style="color:#A6ACCD;">│   │   file011.fits</span></span>
<span class="line"><span style="color:#A6ACCD;">│   │   file012.xisf</span></span>
<span class="line"><span style="color:#A6ACCD;">│   │</span></span>
<span class="line"><span style="color:#A6ACCD;">│   └───subfolder1/</span></span>
<span class="line"><span style="color:#A6ACCD;">│       │   .hidden_file111.txt</span></span>
<span class="line"><span style="color:#A6ACCD;">│       │   file112.asf</span></span>
<span class="line"><span style="color:#A6ACCD;">│       │   ...</span></span>
<span class="line"><span style="color:#A6ACCD;">│   </span></span>
<span class="line"><span style="color:#A6ACCD;">└───folder2/</span></span>
<span class="line"><span style="color:#A6ACCD;">    │   file021.jpeg</span></span>
<span class="line"><span style="color:#A6ACCD;">    │   file022.fts</span></span></code></pre></div><p>There will be 4 Datasets, with the following names:</p><ul><li><code>data</code> containing the DataFiles for <code>README.md</code> and <code>file001.txt</code></li><li><code>data/folder1</code> containing the DataFiles for <code>file011.fits</code> and <code>file012.xisf</code></li><li><code>data/folder1/subfolder1</code> containing the DataFiles for <code>file112.asf</code> only</li><li><code>data/folder2</code> containing the DataFiles for <code>file021.jpeg</code> and <code>file022.fts</code></li></ul><p>Datasets and DataFiles will be tagged with various information (folder name, telescope UUID etc) to help Arcsecond&#39;s backend post-process the files.</p><h2 id="how-files-are-treated" tabindex="-1">How files are treated <a class="header-anchor" href="#how-files-are-treated" aria-label="Permalink to &quot;How files are treated&quot;">​</a></h2><h3 id="file-extensions" tabindex="-1">File extensions <a class="header-anchor" href="#file-extensions" aria-label="Permalink to &quot;File extensions&quot;">​</a></h3><p>All non-hidden files found in the watch folder or one of its subfolder will be uploaded. Files can have an extension or not (for instance <code>README</code> files will also be uploaded). Hidden files starting with a dot will not be uploaded.</p><p>As for the data, <strong>Oort support XISF and FITS files, zipped or not.</strong> Oort will accept files with the following FITS filename extensions: <code>.fits</code>, <code>.fit</code>, <code>.fts</code>, <code>.ft</code>, <code>.mt</code>, <code>.imfits</code>, <code>.imfit</code>, <code>.uvfits</code>, <code>.uvfit</code>, <code>.pha</code>, <code>.rmf</code>, <code>.arf</code>, <code>.rsp</code>, <code>.pi</code> as well as <code>.xisf</code> ones.</p><p>Moreover, these extensions can be augmented with the following zipped file extensions: <code>.zip</code>, <code>.gz</code>, <code>.bz2</code></p><h3 id="file-compression" tabindex="-1">File compression <a class="header-anchor" href="#file-compression" aria-label="Permalink to &quot;File compression&quot;">​</a></h3><p>Files to be uploaded can be already compressed or not. Oort is able to deal with any of them transparently.</p><p>If a XISF or FITS file is being detected and the zip option is set (in the <code>watch</code> command), it will be zipped (with standard) <code>gzip</code> compression before being uploaded. The compression is made locally just beside the original file. That latter file will be deleted once the zip is done (as would a normal <code>gzip</code> command do in the terminal).</p><p><strong>Oort includes an interruption handler that will stop any zip process running</strong>, would any problem occurs preventing the process to complete. More precisely it will stop zip processes on <code>SIGINT</code>, <code>SIGQUIT</code> and <code>SIGTERM</code>.</p><p>Of course, if the folder is read-only for its user, no zipping will be made.</p><h2 id="additional-things-you-must-be-aware-of" tabindex="-1">Additional things you must be aware of <a class="header-anchor" href="#additional-things-you-must-be-aware-of" aria-label="Permalink to &quot;Additional things you must be aware of&quot;">​</a></h2><ul><li>There is no need to install or run Oort as <code>root</code>.</li><li>One must login first before uploading, with the command <code>oort login</code>. It will locally store the necessary credentials used for uploading. <strong>Keep these credentials safe</strong>.</li><li>Note that <code>oort login</code> fetches a limited-scope upload key, just enough to perform its task.</li><li>If uploading for an Observatory Portal, Oort must necessarily be run by a member of it (quite obviously), with role <code>member</code> or above. See <a href="https://docs.arcsecond.io/portals/permissions" target="_blank" rel="noreferrer">permissions</a> for more details.</li><li>This tool is open-source obviously to let anyone sees it doesn&#39;t send or use data that has not explicitly marked for uploading. It is also open for modification, or improvement. Please, use the standard GitHub pull-request mechanism.</li><li>The only auxiliary data that is collected and attached as tag of the files and datasets is the machine hostname (the output of the <code>uname -n</code> command). See inside <code>oort/uploader/engine/preparator.py</code> and <code>uploader. py</code> for the line <code>socket.gethostname()</code>.</li><li>Oort keeps all its metadata inside a hidden folder in <code>~/.oort/</code>. Be careful not modifying the content of it without knowing what you do.</li></ul>`,86),r=[l];function i(c,d,p,h,u,f){return o(),a("div",null,r)}const y=e(n,[["render",i]]);export{g as __pageData,y as default};
